// src/services/clinicService.js
import axios from 'axios';

const API_BASE_URL = 'http://localhost:5000'; // Your backend URL

const clinicService = {
  // Get all clinics
  getClinics: async () => {
    try {
      console.log('🔍 Fetching clinics from backend...');
      const response = await axios.get(`${API_BASE_URL}/clinics`);
      console.log('✅ Clinics fetched successfully:', response.data);
      return response.data;
    } catch (error) {
      console.error('❌ Error fetching clinics:', error);
      
      // Return mock data if API fails
      console.log('🔄 Using mock data as fallback');
      return {
        clinics: [
          {
            id: 1,
            Name: "Smile Dental Care",
            Specialty: "General Dentistry",
            Address: "123 Main Street",
            City: "Mumbai",
            State: "Maharashtra",
            Rating: "4.8",
            Website: "https://smiledentalcare.com",
            Image: "https://images.unsplash.com/photo-1506744038136-46273834b3fb?auto=format&fit=facearea&w=400&h=300&q=80",
            OpenTime: "09:00 AM",
            CloseTime: "08:00 PM",
            Contact: "+91 9876543210",
            Offers: "10% off on first visit",
            Directions: "https://goo.gl/maps/xyz123"
          },
          {
            id: 2,
            Name: "Pearl Dental Studio",
            Specialty: "Cosmetic Dentistry",
            Address: "456 Park Avenue",
            City: "Delhi",
            State: "Delhi",
            Rating: "4.6",
            Website: "https://pearldentalstudio.com",
            Image: "https://images.unsplash.com/photo-1515378791036-0648a3ef77b2?auto=format&fit=facearea&w=400&h=300&q=80",
            OpenTime: "10:00 AM",
            CloseTime: "07:00 PM",
            Contact: "+91 9988776655",
            Offers: "Free consultation for new patients",
            Directions: "https://goo.gl/maps/abc456"
          }
        ]
      };
    }
  },

  // Get clinic by ID
  getClinicById: async (id) => {
    try {
      const response = await axios.get(`${API_BASE_URL}/clinics/${id}`);
      return response.data;
    } catch (error) {
      console.error('Error fetching clinic:', error);
      throw error;
    }
  },

  // Create new clinic
  createClinic: async (clinicData) => {
    try {
      const response = await axios.post(`${API_BASE_URL}/clinics`, clinicData);
      return response.data;
    } catch (error) {
      console.error('Error creating clinic:', error);
      throw error;
    }
  },

  // Update clinic
  updateClinic: async (id, clinicData) => {
    try {
      const response = await axios.put(`${API_BASE_URL}/clinics/${id}`, clinicData);
      return response.data;
    } catch (error) {
      console.error('Error updating clinic:', error);
      throw error;
    }
  },

  // Delete clinic
  deleteClinic: async (id) => {
    try {
      const response = await axios.delete(`${API_BASE_URL}/clinics/${id}`);
      return response.data;
    } catch (error) {
      console.error('Error deleting clinic:', error);
      throw error;
    }
  }
};

export default clinicService;